[Interview complete. Problem extracted:]
{
  "title": "Supply Chain Network Design and Planning",
  "description": "Maximize total profit over a 3-month planning horizon for a supply chain network with potential production sites and distribution centers. Decisions include production quantities, transportation flows, inventory levels, and facility opening timing. Profit is revenue from selling products minus production, transportation, inventory holding, and facility opening/operating costs.",
  "problem_type": "mixed_integer",
  "objective": "maximize",
  "objective_description": "Total profit = total revenue minus total cost (production, transportation, inventory holding, facility opening and operating costs).",
  "constraints": [
    {
      "description": "Production capacity: For each production site i and period t, total production across all products cannot exceed production_capacity[i,t].",
      "expression": "sum_p production[i,p,t] <= production_capacity[i,t]"
    },
    {
      "description": "Throughput capacity: For each distribution center j and period t, total outbound flow to customers across all products cannot exceed throughput_capacity[j,t].",
      "expression": "sum_k sum_p flow_dc_to_cust[j,k,p,t] <= throughput_capacity[j,t]"
    },
    {
      "description": "Storage capacity at production sites: For each production site i, total inventory across all products at the end of any period cannot exceed storage_capacity_site[i].",
      "expression": "sum_p inventory_site[i,p,t] <= storage_capacity_site[i]"
    },
    {
      "description": "Storage capacity at distribution centers: For each distribution center j, total inventory across all products at the end of any period cannot exceed storage_capacity_dc[j].",
      "expression": "sum_p inventory_dc[j,p,t] <= storage_capacity_dc[j]"
    },
    {
      "description": "Demand fulfillment: For each customer k, product p, and period t, total quantity shipped from all distribution centers must equal demand[k,p,t].",
      "expression": "sum_j flow_dc_to_cust[j,k,p,t] = demand[k,p,t]"
    },
    {
      "description": "Production only if site open: Production at site i in period t can only be positive if the site is open in that period (open_site[i,t]=1).",
      "expression": "sum_p production[i,p,t] <= M * open_site[i,t]"
    },
    {
      "description": "Distribution center open for flow: A distribution center j can only have positive inbound or outbound flow in period t if it is open (open_dc[j,t]=1).",
      "expression": "sum_i sum_p flow_prod_to_dc[i,j,p,t] + sum_k sum_p flow_dc_to_cust[j,k,p,t] <= M * open_dc[j,t]"
    },
    {
      "description": "Inventory balance at production sites: For each product p, site i, and period t, inventory at end of previous period plus production equals shipments to DCs plus inventory at end of current period.",
      "expression": "inventory_site[i,p,t-1] + production[i,p,t] = sum_j flow_prod_to_dc[i,j,p,t] + inventory_site[i,p,t]"
    },
    {
      "description": "Inventory balance at distribution centers: For each product p, DC j, and period t, inventory at end of previous period plus inbound from sites equals outbound to customers plus inventory at end of current period.",
      "expression": "inventory_dc[j,p,t-1] + sum_i flow_prod_to_dc[i,j,p,t] = sum_k flow_dc_to_cust[j,k,p,t] + inventory_dc[j,p,t]"
    },
    {
      "description": "Facility opening persistence: Once a production site or distribution center is opened in a period, it remains open for all subsequent periods.",
      "expression": "open_site[i,t] >= open_site[i,t-1]; open_dc[j,t] >= open_dc[j,t-1]"
    }
  ],
  "decision_variables": [
    "production[i,p,t]: Amount of product p produced at production site i in period t (continuous, nonnegative).",
    "flow_prod_to_dc[i,j,p,t]: Quantity of product p shipped from production site i to distribution center j in period t (continuous, nonnegative).",
    "flow_dc_to_cust[j,k,p,t]: Quantity of product p shipped from distribution center j to customer k in period t (continuous, nonnegative).",
    "inventory_site[i,p,t]: Inventory of product p held at production site i at the end of period t (continuous, nonnegative).",
    "inventory_dc[j,p,t]: Inventory of product p held at distribution center j at the end of period t (continuous, nonnegative).",
    "open_site[i,t]: Binary variable indicating whether production site i is open in period t (1 if open, 0 otherwise).",
    "open_dc[j,t]: Binary variable indicating whether distribution center j is open in period t (1 if open, 0 otherwise)."
  ],
  "additional_notes": "Indices: i (production sites), j (distribution centers), k (customers), p (products), t (time periods 1..3). Parameters are as described in the conversation. M is a sufficiently large number for big-M constraints.",
  "csv_file_paths": {}
}
